+    message: boundedText(ERROR_MESSAGE_MAX_LENGTH),
+    request_id: boundedText(REQUEST_ID_MAX_LENGTH),
+  })
+  .strict();
+export type ApiError = z.infer<typeof apiErrorSchema>;
+
+export const memoryMediaTypeSchema = z.enum(["image", "audio", "video"]);
